<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>2048</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #1a1a2e;
    color: #eee;
    font-family: 'Segoe UI', Arial, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    user-select: none;
  }
  h1 {
    font-size: 3rem;
    margin-bottom: 0.5rem;
    color: #e0e0e0;
    letter-spacing: 2px;
  }
  #score {
    font-size: 1.4rem;
    margin-bottom: 1rem;
    color: #ccc;
  }
  #board {
    display: grid;
    grid-template-columns: repeat(4, 100px);
    grid-template-rows: repeat(4, 100px);
    gap: 8px;
    background: #16213e;
    border-radius: 12px;
    padding: 8px;
    box-shadow: 0 4px 24px rgba(0,0,0,0.5);
  }
  .cell {
    width: 100px;
    height: 100px;
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 1.8rem;
    background: #0f3460;
    color: #eee;
    transition: background 0.15s, transform 0.15s;
  }
  .cell[data-val="0"] { background: #1a1a3e; color: transparent; }
  .cell[data-val="2"]  { background: #4a6fa5; }
  .cell[data-val="4"]  { background: #5b7fbf; }
  .cell[data-val="8"]  { background: #e67e22; }
  .cell[data-val="16"] { background: #d35400; }
  .cell[data-val="32"] { background: #e74c3c; }
  .cell[data-val="64"] { background: #c0392b; }
  .cell[data-val="128"] { background: #f1c40f; font-size: 1.6rem; }
  .cell[data-val="256"] { background: #f39c12; font-size: 1.6rem; }
  .cell[data-val="512"] { background: #e67e22; font-size: 1.6rem; }
  .cell[data-val="1024"] { background: #2ecc71; font-size: 1.3rem; }
  .cell[data-val="2048"] { background: #27ae60; font-size: 1.3rem; }
  #reset {
    margin-top: 1.2rem;
    padding: 0.6rem 2rem;
    font-size: 1.1rem;
    border: none;
    border-radius: 8px;
    background: #e94560;
    color: #fff;
    cursor: pointer;
    transition: background 0.2s;
  }
  #reset:hover { background: #c0392b; }
</style>
</head>
<body>
<h1>2048</h1>
<div id="score">Score: 0</div>
<div id="board"></div>
<button id="reset">New Game</button>

<script>
(function() {
  const SIZE = 4;
  let grid = [];
  let scoreVal = 0;

  function createGrid() {
    return Array.from({length: SIZE}, () => Array(SIZE).fill(0));
  }

  function cloneGrid(g) {
    return g.map(r => [...r]);
  }

  function emptyCells(g) {
    const cells = [];
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (g[r][c] === 0) cells.push([r, c]);
    return cells;
  }

  function spawnTile(g) {
    const empties = emptyCells(g);
    if (empties.length === 0) return false;
    const [r, c] = empties[Math.floor(Math.random() * empties.length)];
    g[r][c] = Math.random() < 0.9 ? 2 : 4;
    return true;
  }

  // Slide a single line (array) toward index 0, merging equal values.
  // Returns { line, addedScore, changed }.
  function slideLine(line) {
    // Remove zeros
    let compact = line.filter(v => v !== 0);
    let addedScore = 0;
    let changed = false;

    // Merge adjacent equals (once per pair)
    let merged = [];
    let i = 0;
    while (i < compact.length) {
      if (i + 1 < compact.length && compact[i] === compact[i + 1]) {
        merged.push(compact[i] * 2);
        addedScore += compact[i] * 2;
        changed = true;
        i += 2;
      } else {
        merged.push(compact[i]);
        i++;
      }
    }

    // Pad with zeros
    while (merged.length < SIZE) merged.push(0);

    // Check if anything changed
    if (!changed) {
      for (let j = 0; j < SIZE; j++) {
        if (merged[j] !== line[j]) { changed = true; break; }
      }
    }

    return { line: merged, addedScore, changed };
  }

  function doMove(dir) {
    let totalAdded = 0;
    let anyChanged = false;
    const newGrid = cloneGrid(grid);

    if (dir === 'left') {
      for (let r = 0; r < SIZE; r++) {
        const result = slideLine(newGrid[r]);
        newGrid[r] = result.line;
        totalAdded += result.addedScore;
        if (result.changed) anyChanged = true;
      }
    } else if (dir === 'right') {
      for (let r = 0; r < SIZE; r++) {
        const reversed = [...newGrid[r]].reverse();
        const result = slideLine(reversed);
        newGrid[r] = result.line.reverse();
        totalAdded += result.addedScore;
        if (result.changed) anyChanged = true;
      }
    } else if (dir === 'up') {
      for (let c = 0; c < SIZE; c++) {
        let col = [];
        for (let r = 0; r < SIZE; r++) col.push(newGrid[r][c]);
        const result = slideLine(col);
        for (let r = 0; r < SIZE; r++) newGrid[r][c] = result.line[r];
        totalAdded += result.addedScore;
        if (result.changed) anyChanged = true;
      }
    } else if (dir === 'down') {
      for (let c = 0; c < SIZE; c++) {
        let col = [];
        for (let r = 0; r < SIZE; r++) col.push(newGrid[r][c]);
        const reversed = col.reverse();
        const result = slideLine(reversed);
        const finalCol = result.line.reverse();
        for (let r = 0; r < SIZE; r++) newGrid[r][c] = finalCol[r];
        totalAdded += result.addedScore;
        if (result.changed) anyChanged = true;
      }
    }

    if (anyChanged) {
      grid = newGrid;
      scoreVal += totalAdded;
      spawnTile(grid);
      render();
      return true;
    }
    return false;
  }

  function reset() {
    grid = createGrid();
    scoreVal = 0;
    spawnTile(grid);
    spawnTile(grid);
    render();
  }

  function render() {
    const boardEl = document.getElementById('board');
    boardEl.innerHTML = '';
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        const cell = document.createElement('div');
        cell.className = 'cell';
        const val = grid[r][c];
        cell.setAttribute('data-val', val);
        cell.textContent = val === 0 ? '' : val;
        boardEl.appendChild(cell);
      }
    }
    document.getElementById('score').textContent = 'Score: ' + scoreVal;
  }

  // Expose API
  window.game = {
    size: SIZE,
    reset: reset,
    move: doMove,
    board: function() { return cloneGrid(grid); },
    setBoard: function(arr) {
      grid = arr.map(r => [...r]);
      render();
    },
    score: function() { return scoreVal; }
  };

  // Keyboard control
  document.addEventListener('keydown', function(e) {
    const keyMap = {
      ArrowLeft: 'left',
      ArrowRight: 'right',
      ArrowUp: 'up',
      ArrowDown: 'down'
    };
    if (keyMap[e.key]) {
      e.preventDefault();
      doMove(keyMap[e.key]);
    }
  });

  document.getElementById('reset').addEventListener('click', reset);

  // Start
  reset();
})();
</script>
</body>
</html>
